INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES ("2030/01/01 14:59:59", "カリン", 20047, -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 20047003, 1, "2023/11/16 15:00:00", 190801, 2.801, 3, 2, 0.0, 54);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES ("2030/01/01 14:59:59", "カリン", 20047, -416.5, "報酬がもらえますよ！\nチェックしてみてください", 20047004, 2, "2023/11/16 15:00:00", 190801, 0.0, 4, 2, 0.0, 54);
