INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES ("2030/01/01 14:59:59", "カリン", 20047, -363.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 20047006, 1, "2023/11/16 15:00:00", 190801, 5.506, 1, 2, 0.0, 55);
